# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException

app = Flask(__name__)

ELASTICSEARCH_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ELASTICSEARCH_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
ELASTICSEARCH_TIMEOUT = int(os.getenv("ELASTICSEARCH_TIMEOUT", "2"))
ELASTICSEARCH_MAXSIZE = int(os.getenv("ELASTICSEARCH_MAXSIZE", "50"))
SEARCH_RESULT_SIZE = int(os.getenv("SEARCH_RESULT_SIZE", "20"))

es = Elasticsearch(
    ELASTICSEARCH_URL,
    request_timeout=ELASTICSEARCH_TIMEOUT,
    max_retries=2,
    retry_on_timeout=True,
    connections_per_node=ELASTICSEARCH_MAXSIZE,
)

@app.get("/api/search")
def search_products():
    query = request.args.get("q", "", type=str).strip()

    if not query:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    body = {
        "size": SEARCH_RESULT_SIZE,
        "track_total_hits": False,
        "_source": ["id", "name", "description", "price", "currency", "image_url", "category", "in_stock"],
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": query,
                            "fields": ["name^4", "category^2", "description"],
                            "type": "best_fields",
                            "operator": "and",
                            "fuzziness": "AUTO"
                        }
                    },
                    {
                        "multi_match": {
                            "query": query,
                            "fields": ["name^6", "category^3"],
                            "type": "phrase",
                            "boost": 2
                        }
                    }
                ],
                "minimum_should_match": 1
            }
        }
    }

    try:
        response = es.search(index=ELASTICSEARCH_INDEX, body=body)
        hits = response.get("hits", {}).get("hits", [])
        products = [
            {
                "id": hit.get("_source", {}).get("id", hit.get("_id")),
                "score": hit.get("_score"),
                **hit.get("_source", {})
            }
            for hit in hits
        ]
        return jsonify({
            "query": query,
            "count": len(products),
            "products": products
        }), 200
    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")), threaded=True)